SELECT [DDT_Picking Line].[Order No_], [DDT_Picking Line].[Order Line No_], [DDT_Picking Line].Type, [DDT_Picking Header].[Document Type], [DDT_Picking Line].[Document No_], [DDT_Picking Header].Status, Val([No_ of Pairs]) AS PaiaInBollaTotale, Val([Quantity]) AS QuantitaInBollaTotale, [DDT_Picking Header].[Posted Date] AS DataRegistrazione, [DDT_Picking Header].[Posted No_], [DDT_Picking Header].[Shipment Method Code], [DDT_Picking Header].[Shipping Agent Code], [Shipment Method].Description, [Shipping Agent].Name, [DDT_Picking Header].[Sell-to Customer Name], [DDT_Picking Header].[Sell-to Customer Name 2], [DDT_Picking Header].[Sell-to Customer No_], [DDT_Picking Header].[Ship-to Code], [DDT_Picking Header].[Ship-to Name], [DDT_Picking Header].[Ship-to Name 2], [DDT_Picking Header].[Ship-to Address], [DDT_Picking Header].[Ship-to Address 2], [DDT_Picking Header].[Ship-to City], [DDT_Picking Header].[Ship-to Contact], [DDT_Picking Header].[Ship-to Post Code], [DDT_Picking Header].[Ship-to County], [DDT_Picking Header].[Ship-to Country Code], Item.[Trademark Code], Item.[Season Code], Item.[Collection Code]
FROM ((([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON ([DDT_Picking Line].[Document Type] = [DDT_Picking Header].[Document Type]) AND ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_)) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) LEFT JOIN [Shipment Method] ON [DDT_Picking Header].[Shipment Method Code] = [Shipment Method].Code) LEFT JOIN [Shipping Agent] ON [DDT_Picking Header].[Shipping Agent Code] = [Shipping Agent].Code
WHERE ((([DDT_Picking Line].Type)=19 Or ([DDT_Picking Line].Type)=20) AND (([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Header].Status)=20) AND (([DDT_Picking Header].[Posted Date]) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]));

